#include <stdio.h>
#include <stdlib.h>

int main() {
    int T;
    scanf("%d", &T);
    while (T--) {
        int N, a, b;
        scanf("%d %d %d", &N, &a, &b);
        int* A = (int*) malloc(N * sizeof(int));
        for (int i = 0; i < N; i++) {
            scanf("%d", &A[i]);
        }
        int turn = 0;
        while (1) {
            int removed = 0;
            if (turn == 0) {
                for (int i = 0; i < N; i++) {
                    if (A[i] % a == 0) {
                        A[i] = 0;
                        removed++;
                    }
                }
            } else {
                for (int i = 0; i < N; i++) {
                    if (A[i] % b == 0) {
                        A[i] = 0;
                        removed++;
                    }
                }
            }
            if (removed == 0) {
                break;
            }
            turn = 1 - turn;
        }
        if (turn == 0) {
            printf("ALICE\n");
        } else {
            printf("BOB\n");
        }
        free(A);
    }
    return 0;
}

